import asyncio, os, json
from agents.project_manager.board_client import GitHubProjectBoardClient, DefaultBoardHttpClient

PROJECT_URL = "https://github.com/orgs/trilogy-group/projects/718"
token = os.environ.get("GITHUB_TOKEN", "")

async def main():
    client = GitHubProjectBoardClient(http_client=DefaultBoardHttpClient(), token=token)
    # fetch raw items including closed - need custom query since list_open_items filters OPEN only
    import httpx
    from agents.github_project_change_detector.normaliser import parse_project_identifier
    owner, number = parse_project_identifier(project_url=PROJECT_URL)
    query = """
    query FetchBoardItems($owner: String!, $number: Int!, $cursor: String) {
      organization(login: $owner) {
        projectV2(number: $number) {
          title
          items(first: 100, after: $cursor) {
            pageInfo { hasNextPage endCursor }
            nodes {
              id
              fieldValueByName(name: "Status") {
                ... on ProjectV2ItemFieldSingleSelectValue { name }
              }
              content {
                __typename
                ... on Issue {
                  number
                  title
                  body
                  state
                  repository { name owner { login } }
                }
              }
            }
          }
        }
      }
    }
    """
    headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}
    all_items = []
    cursor = None
    async with httpx.AsyncClient(timeout=60) as http:
        while True:
            variables = {"owner": owner, "number": number, "cursor": cursor}
            r = await http.post("https://api.github.com/graphql", json={"query": query, "variables": variables}, headers=headers)
            data = r.json()
            if "errors" in data:
                print(json.dumps(data["errors"], indent=2))
                return
            proj = data["data"]["organization"]["projectV2"]
            print("PROJECT:", proj["title"])
            items = proj["items"]
            all_items.extend(items["nodes"])
            if not items["pageInfo"]["hasNextPage"]:
                break
            cursor = items["pageInfo"]["endCursor"]

    done = []
    for node in all_items:
        fv = node.get("fieldValueByName") or {}
        status = fv.get("name")
        content = node.get("content") or {}
        if content.get("__typename") != "Issue":
            continue
        if status and status.lower() == "done":
            repo = content["repository"]
            owner_login = repo["owner"]["login"]
            repo_name = repo["name"]
            num = content["number"]
            done.append({
                "url": f"https://github.com/{owner_login}/{repo_name}/issues/{num}",
                "title": content.get("title"),
                "body": content.get("body") or "",
                "state": content.get("state"),
            })
    print(f"DONE_COUNT={len(done)}")
    for d in done:
        print("---")
        print(d["url"])
        print("TITLE:", d["title"])
        print("BODY_LEN:", len(d["body"]))

asyncio.run(main())
